svg.script:
(function () {
  var PHASES = [
    'Two nitrogen atoms, each with unpaired electrons…',
    'Drifting toward each other…',
    'First bond forms!',
    'Two bonds!',
    'Triple bond — the strongest grip in nature!'
  ];

  function setPhase(txt) {
    var el = document.getElementById('n2tb-phase');
    if (el) el.textContent = txt;
  }

  function animate() {
    gsap.set('#n2tb-atom-left',  { x: -80 });
    gsap.set('#n2tb-atom-right', { x:  80 });
    gsap.set('#n2tb-bond1',      { scaleX: 0, opacity: 0 });
    gsap.set('#n2tb-bond2',      { scaleX: 0, opacity: 0 });
    gsap.set('#n2tb-bond3',      { scaleX: 0, opacity: 0 });
    gsap.set('#n2tb-flash',      { opacity: 0 });
    gsap.set('#n2tb-label',      { opacity: 0, y: 12 });
    gsap.set('#n2tb-sublabel',   { opacity: 0 });
    gsap.set('#n2tb-replay',     { opacity: 0 });
    gsap.set('#n2tb-phase',      { opacity: 0 });

    var tl = gsap.timeline();

    tl
      .call(function () { setPhase(PHASES[0]); })
      .to('#n2tb-phase', { opacity: 1, duration: 0.6 })

      /* atoms approach */
      .call(function () { setPhase(PHASES[1]); }, null, '+=0.38')
      .to('#n2tb-atom-left',  { x: 0, duration: 1.65, ease: 'power2.inOut' }, '<')
      .to('#n2tb-atom-right', { x: 0, duration: 1.65, ease: 'power2.inOut' }, '<')

      /* middle bond snaps in first for impact */
      .call(function () { setPhase(PHASES[2]); })
      .to('#n2tb-bond2', { scaleX: 1, opacity: 1, duration: 0.42, ease: 'back.out(2)' })

      /* top bond */
      .call(function () { setPhase(PHASES[3]); }, null, '+=0.23')
      .to('#n2tb-bond1', { scaleX: 1, opacity: 1, duration: 0.42, ease: 'back.out(2)' })

      /* bottom bond + flash pulse */
      .call(function () { setPhase(PHASES[4]); }, null, '+=0.23')
      .to('#n2tb-bond3', { scaleX: 1, opacity: 1, duration: 0.33, ease: 'back.out(2)' })
      .to('#n2tb-flash', { opacity: 0.55, duration: 0.18 }, '<')
      .to('#n2tb-flash', { opacity: 0,    duration: 0.83 })

      /* N≡N label floats up */
      .to('#n2tb-label',    { opacity: 1, y: 0, duration: 0.75 }, '-=0.45')
      .to('#n2tb-sublabel', { opacity: 1, duration: 0.6 })

      /* replay button */
      .to('#n2tb-replay', { opacity: 1, duration: 0.53 }, '+=0.3');
  }

  window.n2tbReplay = function () {
    if (window.gsap) animate();
  };

  function setup() {
    var svgEl = document.getElementById('n2tb-svg');
    if (!svgEl) return;
    var played = false;
    var io = new IntersectionObserver(function (entries) {
      if (entries[0].isIntersecting && !played) {
        played = true;
        io.disconnect();
        animate();
      }
    }, { threshold: 0.3 });
    io.observe(svgEl);
  }

  if (window.gsap) {
    setup();
  } else {
    var s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.5/gsap.min.js';
    s.onload = setup;
    document.head.appendChild(s);
  }
}());
